//for="gr_out" event="OnClick"
scwin.gr_out_oncellclick = async function (rowIndex, columnIndex, columnId) {
  var row = rowIndex;
  let objSubmit;

  //선박별 장비 변경내역 확인
  if (ds_outEq.getModifiedIndex().length + ds_outEq.getDeletedData().length > 0 || ds_outEqHold.getModifiedIndex().length + ds_outEqHold.getDeletedData().length > 0 || ds_attach.getModifiedIndex().length + ds_attach.getDeletedData().length > 0 || ds_attach2.getModifiedIndex().length + ds_attach2.getDeletedData().length > 0) {
    let rtn = await $c.win.confirm($p, MSG_CM_CRM_015);
    if (rtn) {
      //submit 처리.
      objSubmit = await $c.sbm.execute($p, sbm_save);
      if (objSubmit.responseJSON.resultDataSet[0].Msg == "SUCC") {
        await scwin.sbm_save_submitdone();
      }
    }
  }
  if (ds_out.getRowStatus(row) == "C") {
    //신규
    $c.gus.cfEnableKeyData($p);
    btn_AddRow.setDisabled(false);
    btn_DeleteRow.setDisabled(false);
    btn_UndoRow.setDisabled(false);
    btn_DeleteRow2.setDisabled(false);
    btn_UndoRow2.setDisabled(false);
    btn_upload.setDisabled(false);
    $c.gus.cfEnableAllBtn($p);
    $c.gus.cfEnableObjects($p, [oRecevInfo, btn_clntPop, btn_linePop, file_del, file_del2, file_del3]);
    ds_outEq.removeAll();
    ds_outEqHold.removeAll();
    ds_attach.removeAll();
    ds_attach2.removeAll();
    gr_outEq.setReadOnly("column", "vsslEqNo", false);
    gr_outEq.setReadOnly("column", "vsslEqNm", false);
    gr_outEq.setReadOnly("column", "eqKndCd", false);
    gr_outEq.setReadOnly("column", "eqNrmCd", false);

    //gr_outEq.setReadOnly("column","vsslEqCnt",false);
  } else {
    $c.gus.cfDisableKeyData($p);
    btn_AddRow.setDisabled(true);
    btn_DeleteRow.setDisabled(true);
    btn_UndoRow.setDisabled(true);
    btn_DeleteRow2.setDisabled(true);
    btn_UndoRow2.setDisabled(true);
    btn_upload.setDisabled(true);
    $c.gus.cfDisableBtn($p, [btn_save]);
    $c.gus.cfDisableObjects($p, [oRecevInfo, btn_clntPop, btn_linePop, file_del, file_del2, file_del3]);
    gr_outEq.setReadOnly("column", "vsslEqNo", true);
    gr_outEq.setReadOnly("column", "vsslEqNm", true);
    gr_outEq.setReadOnly("column", "eqKndCd", true);
    gr_outEq.setReadOnly("column", "eqNrmCd", true);

    //gr_outEq.setReadOnly("column","vsslEqCnt",true);

    // 조회조건
    dma_conditionDetail.set("vsslCd", ds_out.getCellData(row, "vsslCd"));
    dma_conditionDetail.set("shpCoClntNo", ds_out.getCellData(row, "shpCoClntNo"));

    //submit 처리.
    objSubmit = await $c.sbm.execute($p, sbm_retrieveEq);
    if (objSubmit.responseJSON.resultDataSet[0].Msg == "SUCC") {
      await scwin.sbm_retrieveEq_submitdone();
    }

    //submit 처리.
    objSubmit = await $c.sbm.execute($p, sbm_retrieveFile);
    if (objSubmit.responseJSON.resultDataSet[0].Msg == "SUCC") {
      await scwin.sbm_retrieveFile_submitdone();
    }

    //submit 처리.
    objSubmit = await $c.sbm.execute($p, sbm_retrieveFile2);
    if (objSubmit.responseJSON.resultDataSet[0].Msg == "SUCC") {
      await scwin.sbm_retrieveFile2_submitdone();
    }
  }
};
