//(정수부+콤마) +소수부 혹은 (정수부+콤마) 표현
scwin.displayFormatter01 = function (val) {
  if (val == undefined || val == null || val == "") {
    return "";
  } else {
    //소수부 존재시
    if (val.indexOf(".") > -1) {
      let tempChar = val.split(".");
      var intStr = Number(tempChar[0]).toLocaleString();
      var sPrimeNum = tempChar[1];
      return intStr + "." + sPrimeNum;
    }
    //정수부만 존재시
    else {
      return Number(val).toLocaleString();
    }
  }
};
scwin.gr_outEq_eqNrmCd_setFilter = function (rowIndex) {
  if (ds_outEq.getRowCount() > 0) {
    var fn_colFilter = function (cellData, tmpParam, rowIdx) {
      var v_eqKndCd = ds_outEq.getCellData(rowIndex, "eqKndCd");
      if (cellData == v_eqKndCd) {
        return true;
      } else {
        return false;
      }
      // return이 true인 경우 적용하고 false인 경우 넘김
    };
    ds_LkEqNrm.setColumnFilter({
      type: 'func',
      colIndex: 'upperCd',
      key: fn_colFilter,
      condition: 'and'
    });
    ds_LkEqNrm.reform();
  }
};
scwin.gr_outEq_eqNrmCd_setFormatter = function (data, formattedData, rowIndex, colIndex) {
  if (colIndex == 4) {
    var sRtn = formattedData;
    if (ds_outEq.getCellData(rowIndex, "eqNrmCd") == "" && formattedData.trim() == ":") {
      sRtn = "";
    }
    return sRtn;
  }
};
